import sys
from math import gcd

input = sys.stdin.readline

def solve():
    n = int(input())
    a = list(map(int, input().split()))
    if n == 1:
        print(1)
        return

    d = [abs(a[i+1] - a[i]) for i in range(n-1)]

    best = 1
    # groups: list of (gcd_value, start_index)
    groups = []

    for j, val in enumerate(d):
        new_groups = []
        for g, s in groups:
            ng = gcd(g, val)
            if new_groups and new_groups[-1][0] == ng:
                pass  # same gcd, keep earliest start (new_groups[-1][1] is earlier)
            else:
                new_groups.append((ng, s))
        if new_groups and new_groups[-1][0] == val:
            pass
        else:
            new_groups.append((val, j))
        groups = new_groups

        for g, s in groups:
            if g > 1:
                best = max(best, j - s + 2)  # +2 because subarray of a is one longer

    print(best)

t = int(input())
for _ in range(t):
    solve()

